#include "hirct/Target/GenTB.h"

#include "hirct/Analysis/IRAnalysis.h"
#include <cerrno>
#include <fstream>
#include <iostream>
#include <sys/stat.h>

namespace hirct {

static constexpr const char *AUTO_GENERATED_HEADER_SV =
    "// AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

GenTB::GenTB(circt::hw::HWModuleOp hw_module, mlir::ModuleOp mlir_module)
    : hw_module_(hw_module), mlir_module_(mlir_module),
      symbol_table_(std::make_unique<mlir::SymbolTable>(mlir_module)) {}

bool GenTB::emit(const std::string &output_dir) {
  struct SP {
    std::string name;
    std::string dir;
    int width;
  };
  std::string name = hw_module_.getSymName().str();
  std::vector<SP> ports;
  for (const auto &p : hirct::get_ports(hw_module_))
    ports.push_back({p.name, p.is_input ? "in" : "out",
                     static_cast<int>(p.width ? p.width : 1)});

  std::string clock_name, reset_name;
  bool active_low = false;
  for (const auto &p : ports) {
    if (clock_name.empty() && hirct::is_clock_port(p.name))
      clock_name = p.name;
    if (reset_name.empty() && hirct::is_reset_port(p.name)) {
      reset_name = p.name;
      active_low = hirct::is_active_low_reset(p.name);
    }
  }
  bool has_clock = !clock_name.empty();

  std::string tb_dir = output_dir + "/tb";
  if (mkdir(tb_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    std::cerr << "GenTB: cannot create directory: " << tb_dir << "\n";
    return false;
  }
  std::ofstream ofs(tb_dir + "/" + name + "_tb.sv");
  if (!ofs)
    return false;

  ofs << AUTO_GENERATED_HEADER_SV;
  if (has_clock)
    ofs << "`timescale 1ns / 1ps\n";
  ofs << "\nmodule " << name << "_tb;\n\n";

  for (const auto &p : ports) {
    std::string sv_type =
        (p.width > 1) ? "[" + std::to_string(p.width - 1) + ":0]" : "";
    if (p.dir == "in")
      ofs << "  reg " << sv_type << " " << p.name << ";\n";
    else
      ofs << "  wire " << sv_type << " " << p.name << ";\n";
  }
  ofs << "\n  " << name << " dut(\n";
  for (size_t i = 0; i < ports.size(); ++i) {
    ofs << "    ." << ports[i].name << "(" << ports[i].name << ")";
    if (i + 1 < ports.size())
      ofs << ",";
    ofs << "\n";
  }
  ofs << "  );\n";

  if (has_clock) {
    ofs << "\n  initial " << clock_name << " = 0;\n";
    ofs << "  always #5 " << clock_name << " = ~" << clock_name << ";\n";
    ofs << "\n  initial begin\n";
    if (!reset_name.empty()) {
      ofs << "    " << reset_name << " = " << (active_low ? "0" : "1")
          << ";\n";
      ofs << "    #20;\n";
      ofs << "    " << reset_name << " = " << (active_low ? "1" : "0")
          << ";\n";
    }
    ofs << "    #1000;\n";
    ofs << "    $display(\"PASS: " << name << "_tb\");\n";
    ofs << "    $finish;\n";
    ofs << "  end\n";
  } else {
    ofs << "\n  initial begin\n";
    for (const auto &p : ports) {
      if (p.dir == "in")
        ofs << "    " << p.name << " = 0;\n";
    }
    ofs << "    #10;\n";
    ofs << "    $display(\"PASS: " << name << "_tb\");\n";
    ofs << "    $finish;\n";
    ofs << "  end\n";
  }
  ofs << "\nendmodule\n";
  return true;
}

} // namespace hirct
